// ─────────────────────────────────────────────
// VHSYS :: employers_plus (INTEGRATED WITH employers_plus_info)
// Rota   : POST /employers_plus  
// Fase 4 : Fluxo EMPLOYERS completo
// ─────────────────────────────────────────────
// Input  : { xml_ref?: string, LayerLista?: string }
// Output : { message: '...', transformed_data: {...} } HTTP 201
// Banco  : UPSERT employersData + UPSERT/DELETE dependents + UPSERT/DELETE benefits  
// Chave  : matricula (main), hash(id+nome_dep) (deps), hash(id+nome_ben) (benefits)
// ─────────────────────────────────────────────
// INTEGRATED: All functionality from employers_plus_info
// ─────────────────────────────────────────────

const body = $input.first().json.body || $input.first().json;

// Aceita xml_ref (formato esperado) ou LayerLista (formato atual da extensão)
const xmlRef = body.xml_ref;
const layerLista = body.LayerLista;

if (!xmlRef && !layerLista) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required field: xml_ref or LayerLista' }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus',
  event: 'input_validated',
  has_xml_ref: !!xmlRef,
  has_layer_lista: !!layerLista,
  level: 'info'
}));

// Função para decodificar entidades HTML
function decodeHtml(str) {
  if (!str || typeof str !== 'string') return str;
  return str
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, ' ')
    .replace(/&iacute;/g, 'í')
    .replace(/&ecirc;/g, 'ê')
    .replace(/&ccedil;/g, 'ç')
    .replace(/&otilde;/g, 'õ')
    .replace(/&aacute;/g, 'á')
    .replace(/&atilde;/g, 'ã')
    .replace(/&eacute;/g, 'é')
    .replace(/&oacute;/g, 'ó')
    .replace(/&uacute;/g, 'ú')
    .replace(/&acirc;/g, 'â')
    .replace(/&ocirc;/g, 'ô')
    .replace(/&ucirc;/g, 'û')
    .replace(/&Aacute;/g, 'Á')
    .replace(/&Eacute;/g, 'É')
    .replace(/&Iacute;/g, 'Í')
    .replace(/&Oacute;/g, 'Ó')
    .replace(/&Uacute;/g, 'Ú')
    .replace(/&Acirc;/g, 'Â')
    .replace(/&Ecirc;/g, 'Ê')
    .replace(/&Icirc;/g, 'Î')
    .replace(/&Ocirc;/g, 'Ô')
    .replace(/&Ucirc;/g, 'Û')
    .replace(/&Atilde;/g, 'Ã')
    .replace(/&Otilde;/g, 'Õ')
    .replace(/&Ccedil;/g, 'Ç');
}

// Extrai dados dos funcionários da tabela HTML (ENHANCED FROM employers_plus_info)
function extractEmployeesFromHtml(htmlString) {
  const employees = [];

  // Regex para extrair as linhas da tabela com dados dos funcionários
  const rowRegex = /<tr[^>]*class="table-row-body"[^>]*codigo="(\d+)"[^>]*>([\s\S]*?)<\/tr>/gi;

  let match;
  while ((match = rowRegex.exec(htmlString)) !== null) {
    const codigo = match[1];
    const rowContent = match[2];

    // Extrai os dados de cada célula da linha
    const cellRegex = /<td[^>]*class="table-item-body"[^>]*data-clickable="true">([^<]*?)<\/td>/gi;
    const cells = [];

    let cellMatch;
    while ((cellMatch = cellRegex.exec(rowContent)) !== null) {
      cells.push(decodeHtml(cellMatch[1].trim()));
    }

    // Verifica se temos pelo menos 3 células (matricula, nome, cargo)
    if (cells.length >= 3) {
      const employee = {
        id_funcionario: codigo,     // Map codigo to id_funcionario
        matricula: cells[0],        // Primeiro campo: matrícula
        nome_funcionario: cells[1], // Segundo campo: nome -> nome_funcionario
        cargo: cells[2],            // Terceiro campo: cargo
        status: 'ativo'            // Todos na listagem parecem estar ativos
      };

      employees.push(employee);
    }
  }

  return employees;
}

let htmlContent;
let employees = [];

// Se tem xml_ref, extrai LayerLista do XML
if (xmlRef) {
  const layerListaMatch = xmlRef.match(/<cmd[^>]*t=["']LayerLista["'][^>]*><!\[CDATA\[([\s\S]*?)\]\]><\/cmd>/i);
  if (!layerListaMatch) {
    return {
      _valid: false,
      statusCode: 400,
      body: { ok: false, error: 'LayerLista not found in XML' }
    };
  }
  htmlContent = layerListaMatch[1];
} else {
  // Usa LayerLista direto
  htmlContent = layerLista;
}

// Valida que temos dados HTML
if (!htmlContent || !htmlContent.includes('table-row-body')) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Invalid HTML table data' }
  };
}

// Extrai a lista de funcionários
employees = extractEmployeesFromHtml(htmlContent);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus',
  event: 'html_table_parsed',
  employees_found: employees.length,
  level: 'info'
}));

if (employees.length === 0) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'No employees found in HTML table' }
  };
}

// Retorna dados validados para processamento
return { _valid: true, employees };

// Processa dados de funcionários (INTEGRATED) - mantém estrutura para compatibilidade
const ctx = $input.first().json;
const employees = ctx.employees;

// Processa cada funcionário mantendo estrutura original mas usando campos corretos
const processedEmployees = employees.map(emp => {
  // Normaliza dados do funcionário usando matricula como chave principal
  const id_funcionario = String(emp.id_funcionario || '').trim();
  const matricula = String(emp.matricula || '').trim();
  const nome_funcionario = String(emp.nome_funcionario || '').trim();
  const cargo = String(emp.cargo || '').trim();
  const status = String(emp.status || 'ativo').trim();

  return {
    id_funcionario: id_funcionario,     // Mantém para compatibilidade
    matricula: matricula,               // Chave principal (PRIMARY KEY)
    nome_funcionario: nome_funcionario, // Already decoded in Validate Input
    cargo: cargo,
    status: status
  };
});

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus',
  event: 'employees_processed',
  employees_count: processedEmployees.length,
  level: 'info'
}));

return processedEmployees;

// Build success response for processed employees (MODIFIED - Returns IDs for loop)
const results = $input.all();
const processedEmployees = results.map(item => {
  // O PostgreSQL retorna o resultado da query no formato { id_funcionario: 'xxx', nome_funcionario: 'yyy' }
  if (item.json && item.json.id_funcionario) {
    return {
      codigo: item.json.id_funcionario,  // CHANGED: codigo instead of id_funcionario for compatibility
      id_funcionario: item.json.id_funcionario,
      nome_funcionario: item.json.nome_funcionario || 'Unknown',
      matricula: item.json.matricula || '',
      cargo: item.json.cargo || '',
      status: item.json.status || 'ativo'
    };
  }
  return null;
}).filter(emp => emp !== null);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus',
  event: 'employees_processing_completed',
  total_processed: processedEmployees.length,
  level: 'info'
}));

// MODIFIED: Return format compatible with extension expectation
return {
  statusCode: 201,
  body: {
    message: `Successfully processed ${processedEmployees.length} employees.`,
    processed_employees: processedEmployees,
    employees_processed: processedEmployees.length,
    total_count: processedEmployees.length,
    ids: processedEmployees  // ADDED: ids array for loop processing
  }
};

// Funcionário não existe na base - erro
const ctx = $('Process Employee Data').all()
  .find(item => item.json.matricula === $input.first().json.matricula);

const matricula = ctx ? ctx.json.matricula : 'unknown';

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus',
  event: 'employee_not_found',
  matricula: matricula,
  level: 'error'
}));

return {
  statusCode: 404,
  body: { 
    ok: false, 
    error: 'Employee not found', 
    message: `Employee with matricula ${matricula} does not exist in database` 
  }
};

// Erro de validação
const input = $input.first().json;
return {
  statusCode: input.statusCode || 400,
  body: input.body || { ok: false, error: 'Validation failed' }
};

// Extract employee IDs for individual processing
const response = $input.first().json;

// Check if we have the response with ids array
if (!response.body || !response.body.ids) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'employers_plus_individual_loop',
    event: 'no_ids_found_skipping_individual_processing',
    level: 'info'
  }));

  // Return original response - no individual processing needed
  return response;
}

const ids = response.body.ids;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus_individual_loop',
  event: 'starting_individual_employee_processing',
  total_employees: ids.length,
  level: 'info'
}));

// Return each employee ID as separate items for the loop
return ids.map(employee => ({
  codigo: employee.codigo,
  id_funcionario: employee.id_funcionario,
  nome_funcionario: employee.nome_funcionario,
  matricula: employee.matricula,
  cargo: employee.cargo,
  status: employee.status
}));

// CORRECTED: Process ALL employees from Split Employee IDs, not just the first one
// Extension will handle individual VHSYS HTTP requests for detailed employee data

// Get ALL employee data that was split by the previous node
const allEmployeeData = $input.all();

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus_individual_loop',
  event: 'processing_all_employees',
  total_employees: allEmployeeData.length,
  note: 'Individual employee data fetching should be handled by Chrome Extension due to authentication requirements',
  level: 'info'
}));

// Process each employee but return the original response with all IDs
// The key insight: we don't need individual processing here, just pass through the complete response
const processedEmployees = allEmployeeData.map(item => {
  const employeeData = item.json;
  return {
    codigo: employeeData.codigo || 'unknown',
    id_funcionario: employeeData.id_funcionario || '',
    nome_funcionario: employeeData.nome_funcionario || 'Unknown',
    matricula: employeeData.matricula || '',
    cargo: employeeData.cargo || '',
    status: employeeData.status || 'ativo'
  };
});

// Return the complete response that the extension expects
return {
  statusCode: 201,
  body: {
    message: `Successfully processed ${processedEmployees.length} employees.`,
    processed_employees: processedEmployees,
    employees_processed: processedEmployees.length,
    total_count: processedEmployees.length,
    ids: processedEmployees  // This is what the extension needs for the loop
  }
};
